import React from "react";
import { ListBox } from "primereact/listbox";
import type { IListBoxSelect } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useKitsTheme } from "../../../contexts/Theme";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useSelectBase } from "../hooks/useSelectBase";

const KitsListBox = (rawProps: IListBoxSelect) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('ListBox', rawProps);
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        label,
        disabled,
        invalid,
        errors,
        helperText,
        inputSize = "md",
        withFilter,
        loading,
        virtualScroll,
        localProps,
        isMultiple,
        filterBy,
        hideError,
        attached,
        containerStyle,
    } = props;

    const { list, keys, onChange, selectedValue } = useSelectBase();

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');

    const Element = (
        <ListBox
            id={id}
            value={selectedValue}
            options={list}
            onChange={(e) => onChange({ target: { value: e.value } }, e.value)}
            {...keys}
            disabled={disabled || loading}
            filter={withFilter}
            filterBy={filterBy ?? 'label'}
            virtualScrollerOptions={virtualScroll}
            multiple={isMultiple}
            className="w-full"
            style={{ borderRadius: 0, border:'none', ...(resolvedRootStyle || resolvedThemeStyle) }}
            listStyle={{ maxHeight: "250px" }}
            pt={{
                root: {
                    style: {
                        borderColor: borderColor,
                    }
                },
                item: ({ context }: any) => context?.selected ? {
                    style: { backgroundColor: primaryColor, color: 'white' }
                } : context?.focused ? {
                    style: { backgroundColor: `color-mix(in srgb, ${primaryColor} 12%, transparent)` }
                } : undefined,
            }}
            {...localProps}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            label={label}
            invalid={!!invalid}
            hideError={hideError}
            helperText={helperText}
            errors={errors}
            inputSize={inputSize}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsListBox;
